// CONFIG
var EXPECTED_SECRET = 'mulligan-secure-8821';
var input = items[0].json;

// 1. HUNT FOR DATA (The "Finder" Logic)
var data = {};

// Strategy A: Is it at the root?
if (input.bookingId) {
    data = input;
}
// Strategy B: Is it inside 'body'?
else if (input.body && input.body.bookingId) {
    data = input.body;
}
// Strategy C: Is 'body' a string we need to parse?
else if (input.body && typeof input.body === 'string') {
    try {
        var parsed = JSON.parse(input.body);
        if (parsed.bookingId) data = parsed;
    } catch (e) {}
}

// 2. VALIDATION (Stop immediately if missing)
if (!data.bookingId) {
    var foundKeys = Object.keys(input).join(", ");
    throw new Error(`CRITICAL: Could not find 'bookingId'. Available keys: [${foundKeys}]`);
}

// 3. SECURITY CHECK
var receivedSecret = data.secret || (input.headers ? input.headers['x-secret'] : '');
if (receivedSecret !== EXPECTED_SECRET) {
     throw new Error(`UNAUTHORIZED: Invalid Secret. Got: ${receivedSecret}`);
}

// 4. RETURN CLEAN DATA (Modern fields from trigger-n8n API)
return {
  json: {
    valid: true,
    bookingId: data.bookingId,
    yocoId: data.yocoId,
    paymentStatus: data.paymentStatus || 'paid',
    guest_name: data.guest_name,
    guest_email: data.guest_email,
    guest_phone: data.guest_phone,
    booking_date: data.booking_date,
    start_time: data.start_time,
    end_time: data.end_time,
    simulator_id: data.simulator_id,
    bay_name: data.bay_name,
    time_slot: data.time_slot,
    player_count: data.player_count || 1,
    duration_hours: data.duration_hours || 1,
    session_type: data.session_type || 'quick',
    session_type_label: data.session_type_label || 'Quick Play',
    addon_coaching: data.addon_coaching || false,
    addon_club_rental: data.addon_club_rental || false,
    total_price: data.total_price || data.totalPrice || '0.00',
    amount_paid: data.amount_paid || data.depositPaid || '0.00',
    amount_due: data.amount_due || data.outstandingBalance || '0.00',
    payment_type: data.payment_type || (data.is_fully_paid ? 'full' : 'deposit'),
    is_fully_paid: data.is_fully_paid || false,
    is_short_session: data.is_short_session || (data.duration_hours <= 1),
    payment_summary: data.payment_summary || ''
  }
};

