var booking = $('Validate & Prep').item.json;
var simulatorMap = {1: 'Lounge Bay', 2: 'Middle Bay', 3: 'Window Bay'};
var bayName = booking.bay_name || simulatorMap[booking.simulator_id] || ('Bay ' + booking.simulator_id);

var addonRows = [];
if (booking.addon_coaching) addonRows.push(`<tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Coaching Session</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#059669;font-weight:600;text-align:right;">\u2713 Included</td></tr>`);
if (booking.addon_club_rental) addonRows.push(`<tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;">Club Hire</td><td style="padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#059669;font-weight:600;text-align:right;">\u2713 Included</td></tr>`);
var addonsHtml = addonRows.length > 0 ? addonRows.join('') : '';

var totalPrice = booking.total_price || '0.00';
var amountPaid = booking.amount_paid || '0.00';
var amountDue = booking.amount_due || '0.00';
var isFullyPaid = booking.is_fully_paid || false;
var isShort = booking.is_short_session || false;

var paymentBlock = '';
if (isFullyPaid) {
  paymentBlock = `<div style="background-color:#ecfdf5;border:1px solid #d1fae5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;"><span style="font-size:13px;color:#065f46;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;">PAYMENT COMPLETE</span><p style="font-size:28px;font-weight:700;color:#065f46;margin:0;">R${totalPrice} Paid in Full</p></div>`;
} else if (parseFloat(amountPaid) > 0) {
  var label = isShort ? "PAYMENT RECEIVED" : "SECURED VIA DEPOSIT";
  paymentBlock = `<div style="background-color:#ecfdf5;border:1px solid #d1fae5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;"><span style="font-size:13px;color:#065f46;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;">${label}</span><p style="font-size:28px;font-weight:700;color:#065f46;margin:0;">R${amountPaid} Paid</p><div>Balance Due: R${amountDue}</div></div>`;
} else {
  paymentBlock = `<div style="background-color:#fff7ed;border:1px solid #ffedd5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;"><span style="font-size:13px;color:#9a3412;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;">PAYMENT PENDING</span><p style="font-size:28px;font-weight:700;color:#9a3412;margin:0;">R${totalPrice} Due at Venue</p></div>`;
}

var geminiResponse = $('Gemini: Personalized Message').item.json;
var personalizedMsg = (geminiResponse.candidates && geminiResponse.candidates[0] && geminiResponse.candidates[0].content && geminiResponse.candidates[0].content.parts && geminiResponse.candidates[0].content.parts[0]) ? geminiResponse.candidates[0].content.parts[0].text : `Your booking at The Mulligan is confirmed. We've reserved the ${bayName} for you.`;

var html = `<div style="font-family:sans-serif;max-width:600px;margin:0 auto;background:#fff;padding:40px;"><h1>The Mulligan</h1><p>${personalizedMsg}</p>${paymentBlock}<table style="width:100%;"><tr><td>Date</td><td>${booking.booking_date}</td></tr><tr><td>Time</td><td>${booking.start_time}</td></tr><tr><td>Duration</td><td>${booking.duration_hours}h</td></tr></table></div>`;

return {
  json: {
    from: "The Mulligan <bookings@themulligan.org>",
    to: [booking.guest_email],
    subject: `Booking Confirmed: ${booking.booking_date}`,
    html: html
  }
};

var booking = $('Validate & Prep').item.json;
var simulatorMap = {1: 'Lounge Bay', 2: 'Middle Bay', 3: 'Window Bay'};
var bayName = booking.bay_name || simulatorMap[booking.simulator_id] || ('Bay ' + booking.simulator_id);

var addonRows = [];
if (booking.addon_coaching) addonRows.push(`<tr><td>Coaching</td><td>Booked</td></tr>`);
if (booking.addon_club_rental) addonRows.push(`<tr><td>Club Hire</td><td>Booked</td></tr>`);

var totalPrice = booking.total_price || '0.00';
var amountPaid = booking.amount_paid || '0.00';
