var isShort = booking.is_short_session || false;

var paymentLabel = isFullyPaid ? 'PAID IN FULL' : (parseFloat(amountPaid) > 0 ? (isShort ? 'PARTIAL' : 'DEPOSIT') : 'PENDING');

var html = `<div><h2>NEW BOOKING ALERT</h2><p>Guest: ${booking.guest_name}</p><p>Bay: ${bayName}</p><p>Status: ${paymentLabel}</p><p>Balance: R${amountDue}</p></div>`;

return {
  json: {
    from: "The Mulligan <bookings@themulligan.org>",
    to: ["themulligan.store@gmail.com"],
